// ========== PAGE NAVIGATION ==========
function goToPage(pageName) {
    const pages = document.querySelectorAll('.page-section');
    pages.forEach(page => page.classList.remove('active'));

    const selectedPage = document.getElementById(pageName + '-page');
    if (selectedPage) {
        selectedPage.classList.add('active');
    }

    const navLinks = document.querySelectorAll('.nav-link');
    navLinks.forEach(link => link.classList.remove('active'));
    const activeLink = document.querySelector(`.nav-link[data-page="${pageName}"]`);
    if (activeLink) {
        activeLink.classList.add('active');
    }

    const navMenu = document.getElementById('navMenu');
    const mobileMenuBtn = document.getElementById('mobileMenuBtn');
    if (navMenu && mobileMenuBtn) {
        navMenu.classList.remove('active');
        mobileMenuBtn.classList.remove('active');
    }

    window.scrollTo(0, 0);

    if (pageName === 'news') {
        generateNewsGrid();
    }
}

// ========== MOBILE MENU ==========
function toggleMobileMenu() {
    const navMenu = document.getElementById('navMenu');
    const mobileMenuBtn = document.getElementById('mobileMenuBtn');
    if (navMenu && mobileMenuBtn) {
        navMenu.classList.toggle('active');
        mobileMenuBtn.classList.toggle('active');
    }
}

// ========== GENERATE NEWS GRID ==========
function generateNewsGrid() {
    const newsGrid = document.getElementById('newsGrid');
    if (!newsGrid) return;

    newsGrid.innerHTML = newsItems.map(item => `
        <div class="news-card" onclick="showNewsDetail(${item.id})">
            <div class="news-badge">${item.category}</div>
            <div class="news-image">
                ${item.image ? `<img src="${item.image}" alt="${item.title}" style="width:100%;height:100%;object-fit:cover;display:block;">` : item.icon}
            </div>
            <div class="news-content">
                <h3>${item.title}</h3>
                <p class="news-date mono">// ${item.date}</p>
                <p class="news-preview">${item.preview}</p>
                <button class="news-read-more">
                    view_details() <span>→</span>
                </button>
            </div>
        </div>
    `).join('');
}

// ========== SHOW NEWS DETAIL ==========
function showNewsDetail(newsId) {
    const newsItem = newsItems.find(item => item.id === newsId);
    if (!newsItem) return;

    const detailContent = document.getElementById('newsDetailContent');
    if (!detailContent) return;

    const skillsHtml = newsItem.skills ? `
        <div class="meta-item">
            <h4>skills_learned</h4>
            <div class="skills-list">
                ${newsItem.skills.map(skill => `<span class="skill-badge">${skill}</span>`).join('')}
            </div>
        </div>
    ` : '';

    const technologiesHtml = newsItem.technologies ? `
        <div class="meta-item">
            <h4>tech_used</h4>
            <div class="skills-list">
                ${newsItem.technologies.map(tech => `<span class="skill-badge">${tech}</span>`).join('')}
            </div>
        </div>
    ` : '';

    const issuerHtml = newsItem.issuer ? `
        <div class="meta-item">
            <h4>issuer</h4>
            <p>${newsItem.issuer}</p>
        </div>
    ` : '';

    detailContent.innerHTML = `
        <div class="news-detail-header">
            <span class="news-detail-badge">${newsItem.category}</span>
            <h1>${newsItem.title}</h1>
            <p class="news-detail-meta">
                <span>// ${newsItem.date}</span>
                <span class="status-badge">${newsItem.status}</span>
            </p>
        </div>

        <div class="news-detail-body">
            <div class="news-detail-image">
                ${newsItem.image ? `<img src="${newsItem.image}" alt="${newsItem.title}">` : newsItem.icon}
            </div>

            <div class="news-detail-text">
                ${newsItem.fullDescription.split('\n\n').map(para => `<p>${para}</p>`).join('')}
            </div>

            <div class="news-detail-meta-info">
                ${issuerHtml}
                ${skillsHtml}
                ${technologiesHtml}
            </div>
        </div>
    `;

    goToPage('news-detail');
}

// ========== CONTACT FORM SUBMIT ==========
async function handleSubmit(event) {
    event.preventDefault();

    const name = document.getElementById('name').value;
    const email = document.getElementById('email').value;
    const message = document.getElementById('message').value;

    if (name && email && message) {
        const form = document.getElementById('contactForm');
        const successMsg = document.getElementById('successMessage');
        const submitBtn = form.querySelector('button[type="submit"]');

        // Disable button saat loading
        submitBtn.disabled = true;
        submitBtn.querySelector('span').textContent = 'Mengirim...';

        try {
            const response = await fetch('https://api.web3forms.com/submit', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({
                    access_key: '3cd956a2-58e2-497b-87a1-054493af9ded',
                    name: name,
                    email: email,
                    message: message,
                    subject: 'Pesan Baru dari Website - ' + name,
                })
            });

            const result = await response.json();

            if (result.success) {
                form.style.display = 'none';
                successMsg.style.display = 'block';

                setTimeout(() => {
                    form.reset();
                    form.style.display = 'flex';
                    successMsg.style.display = 'none';
                    submitBtn.disabled = false;
                    submitBtn.querySelector('span').textContent = 'Kirim Pesan';
                }, 3000);
            } else {
                alert('Gagal mengirim pesan. Coba lagi ya!');
                submitBtn.disabled = false;
                submitBtn.querySelector('span').textContent = 'Kirim Pesan';
            }
        } catch (error) {
            alert('Terjadi kesalahan. Periksa koneksi internet kamu!');
            submitBtn.disabled = false;
            submitBtn.querySelector('span').textContent = 'Kirim Pesan';
        }
    }
}

